modifier onlyGuardian() {
    require(msg.sender == guardian, "Not guardian");
    _;
}

function emergencyPause() public onlyGuardian {
    // Instantly pause all bot operations
    // Instantly veto any proposal
    // Instantly lock treasury
    paused = true;
}

function vetoProposal(uint256 proposalId) public onlyGuardian {
    // Your safety valve for bad proposals
